<script setup>
import { computed, nextTick, ref, watch } from 'vue';import { Head } from '@inertiajs/vue3';import axios from 'axios';import ParticipantPortalLayout from '@/Layouts/ParticipantPortalLayout.vue';
const props=defineProps({participations:Array,messages:Array});const selectedId=ref(props.participations?.[0]?.id||'');const items=ref([...(props.messages||[])]);const body=ref('');const sending=ref(false);const conversation=ref(null);const thread=computed(()=>items.value.filter(item=>Number(item.project_person_id)===Number(selectedId.value)));const selectedProject=computed(()=>props.participations.find(item=>Number(item.id)===Number(selectedId.value)));
const senderName=(item)=>item.sender_kind==='participant'?'Ich':`${item.sender?.person?.vorname||''} ${item.sender?.person?.nachname||''}`.trim()||item.sender?.username||'Projektteam';const scrollDown=async()=>{await nextTick();if(conversation.value)conversation.value.scrollTop=conversation.value.scrollHeight;};
const markRead=async()=>{if(!selectedId.value)return;await axios.put(route('participant-portal.messages.read',selectedId.value));items.value.filter(item=>Number(item.project_person_id)===Number(selectedId.value)&&item.sender_kind==='staff').forEach(item=>{item.participant_read_at||=new Date().toISOString()});scrollDown();};
const send=async()=>{if(!body.value.trim()||!selectedId.value)return;sending.value=true;try{const r=await axios.post(route('participant-portal.messages.store'),{project_person_id:selectedId.value,body:body.value});items.value.push(r.data.item);body.value='';scrollDown();}finally{sending.value=false;}};watch(selectedId,markRead,{immediate:true});
</script>
<template><Head title="Nachrichten"/><ParticipantPortalLayout title="Nachrichten" subtitle="Tauschen Sie sich sicher und projektbezogen mit Ihrem zuständigen Team aus."><div v-if="participations.length" class="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"><div class="grid min-h-[650px] lg:grid-cols-[280px_1fr]"><aside class="border-b border-slate-200 bg-slate-50 p-4 lg:border-b-0 lg:border-r"><p class="px-2 text-xs font-bold uppercase tracking-wider text-slate-500">Projekte</p><button v-for="p in participations" :key="p.id" type="button" class="mt-2 w-full rounded-xl p-3 text-left transition" :class="Number(selectedId)===Number(p.id)?'bg-slate-950 text-white shadow-lg':'hover:bg-white'" @click="selectedId=p.id"><p class="text-sm font-bold">{{ p.projekt.name }}</p><p class="mt-1 text-xs" :class="Number(selectedId)===Number(p.id)?'text-slate-300':'text-slate-500'">Projektteam</p></button></aside><section class="flex min-w-0 flex-col"><header class="border-b border-slate-100 px-5 py-4"><p class="font-bold">{{ selectedProject?.projekt?.name }}</p><p class="text-xs text-emerald-600">Sichere Projektkommunikation</p></header><div ref="conversation" class="flex-1 space-y-3 overflow-y-auto bg-gradient-to-b from-slate-50 to-white p-5"><article v-for="message in thread" :key="message.id" class="flex" :class="message.sender_kind==='participant'?'justify-end':'justify-start'"><div class="max-w-[85%] rounded-2xl px-4 py-3 shadow-sm sm:max-w-[70%]" :class="message.sender_kind==='participant'?'rounded-br-md bg-slate-950 text-white':'rounded-bl-md border border-slate-200 bg-white text-slate-800'"><p class="text-[11px] font-bold opacity-60">{{ senderName(message) }}</p><p class="mt-1 whitespace-pre-wrap text-sm leading-6">{{ message.body }}</p><p class="mt-1 text-right text-[10px] opacity-50">{{ new Date(message.created_at).toLocaleString('de-DE') }}</p></div></article><div v-if="!thread.length" class="grid h-full min-h-72 place-items-center text-center"><div><div class="mx-auto grid h-14 w-14 place-items-center rounded-2xl bg-slate-100 text-2xl">✉</div><p class="mt-3 font-semibold">Noch keine Nachrichten</p><p class="mt-1 text-sm text-slate-500">Beginnen Sie die Unterhaltung mit Ihrem Projektteam.</p></div></div></div><form class="border-t border-slate-200 bg-white p-4" @submit.prevent="send"><div class="flex items-end gap-3"><textarea v-model="body" maxlength="5000" rows="2" placeholder="Ihre Nachricht …" class="min-h-12 flex-1 resize-none rounded-xl border-slate-300 text-sm focus:border-cyan-500 focus:ring-cyan-500"></textarea><button class="rounded-xl bg-cyan-600 px-5 py-3 text-sm font-bold text-white shadow-sm hover:bg-cyan-700 disabled:opacity-50" :disabled="sending||!body.trim()">{{ sending?'Sendet …':'Senden' }}</button></div></form></section></div></div><div v-else class="rounded-2xl border border-slate-200 bg-white p-10 text-center text-slate-500">Nachrichten sind für keines Ihrer Projekte freigeschaltet.</div></ParticipantPortalLayout></template>
